-- Add reflexive_pronoun_case column to german_verbs
ALTER TABLE public.german_verbs ADD COLUMN IF NOT EXISTS reflexive_pronoun_case text CHECK (reflexive_pronoun_case IN ('akkusativ', 'dativ'));

-- Update all reflexive verbs with their correct case
UPDATE public.german_verbs SET reflexive_pronoun_case = 'akkusativ' WHERE infinitive = 'sich abmelden';
UPDATE public.german_verbs SET reflexive_pronoun_case = 'dativ' WHERE infinitive = 'sich abgewöhnen';
